class Solution {
public:
    int binaryGap(int n) {
        int maxGap = 0, prev = -1;
        int idx = 0;
        while (n) {
            if (n & 1) {
                if (prev != -1) {
                    maxGap = max(maxGap, idx - prev);
                }
                prev = idx;
            }
            idx++;
            n >>= 1;
        }
        return maxGap;
    }
};
